// // This module controls the fan speed based on temperature levels. It has three states: ON, MEDIUM, and OFF. The fan turns ON when the temperature is below 20 degrees, MEDIUM when the temperature is between 20 and 30 degrees, and OFF when the temperature is above 30 degrees. The control is activated on a falling edge of a clock signal.
module fan_speed_control(  
    input wire clk,  
    input wire reset,  
    input wire [7:0] temperature,  
    output reg [1:0] fan_speed  
);  
    parameter OFF = 2'b00, LOW = 2'b01, HIGH = 2'b10;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            fan_speed <= OFF;  
        else begin  
            if (temperature < 20)  
                fan_speed <= OFF;  
            else if (temperature >= 20 && temperature <= 30)  
                fan_speed <= LOW;  
            else  
                fan_speed <= HIGH;  
        end  
    end  
endmodule
